mapper.select:
SELECT USER_ID, EMAIL, EMAIL_VERIFIED
FROM USERS
WHERE EMAIL_VERIFY_TOKEN = #{token}

mapper.update:
UPDATE USERS
SET LOGIN_FAIL_CNT = 0, ACCOUNT_LOCKED = 'N'
WHERE EMAIL = #{email}

UPDATE USERS
SET EMAIL_VERIFIED = 'Y', EMAIL_VERIFY_TOKEN = NULL
WHERE EMAIL_VERIFY_TOKEN = #{token}

UPDATE USERS
SET EMAIL_VERIFY_TOKEN = #{emailVerifyToken}
WHERE USER_ID = #{userId}
